!function(){"use strict";window.AMH&&AMH.register?AMH.register("gallery-glitch",function(a){AMH.injectCSS("gallery-glitch",'[data-amh="gallery-glitch"] .gal-glitch_grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1.5rem}[data-amh="gallery-glitch"] .gal-glitch_item{position:relative;overflow:hidden;aspect-ratio:3/2;cursor:pointer;border-radius:var(--amh-radius-md,0.5rem);border:1px solid var(--amh-border-subtle,rgba(242,242,242,0.08))}[data-amh="gallery-glitch"] .gal-glitch_visual{position:absolute;inset:0}[data-amh="gallery-glitch"] .gal-glitch_item:nth-child(1) .gal-glitch_visual{background:linear-gradient(135deg,rgba(0,182,182,.4),rgba(0,60,120,.3))}[data-amh="gallery-glitch"] .gal-glitch_item:nth-child(2) .gal-glitch_visual{background:radial-gradient(ellipse at 40% 60%,rgba(0,182,182,.4),transparent 60%)}[data-amh="gallery-glitch"] .gal-glitch_item:nth-child(3) .gal-glitch_visual{background:conic-gradient(from 90deg,rgba(0,182,182,.3),rgba(0,0,0,.9),rgba(0,120,180,.25))}[data-amh="gallery-glitch"] .gal-glitch_item:nth-child(4) .gal-glitch_visual{background:linear-gradient(200deg,rgba(0,120,180,.35),rgba(0,182,182,.2))}[data-amh="gallery-glitch"] .gal-glitch_item:nth-child(5) .gal-glitch_visual{background:radial-gradient(circle at 70% 30%,rgba(0,182,182,.4),transparent 55%)}[data-amh="gallery-glitch"] .gal-glitch_item:nth-child(6) .gal-glitch_visual{background:linear-gradient(315deg,rgba(0,80,140,.35),rgba(0,182,182,.2))}[data-amh="gallery-glitch"] .gal-glitch_item::before,[data-amh="gallery-glitch"] .gal-glitch_item::after{content:"";position:absolute;inset:0;opacity:0;pointer-events:none;mix-blend-mode:screen;transition:opacity .2s}[data-amh="gallery-glitch"] .gal-glitch_item::before{background:inherit;background-color:rgba(255,0,0,.3);transform:translate(0,0)}[data-amh="gallery-glitch"] .gal-glitch_item::after{background:inherit;background-color:rgba(0,255,255,.3);transform:translate(0,0)}[data-amh="gallery-glitch"] .gal-glitch_item:hover::before{opacity:1;animation:galGlitchR .3s steps(2) infinite}[data-amh="gallery-glitch"] .gal-glitch_item:hover::after{opacity:1;animation:galGlitchC .3s steps(3) infinite .05s}[data-amh="gallery-glitch"] .gal-glitch_item:hover .gal-glitch_visual{animation:galGlitchSlice .4s steps(4) infinite}@keyframes galGlitchR{0%{transform:translate(3px,-2px)}25%{transform:translate(-2px,3px)}50%{transform:translate(1px,1px)}75%{transform:translate(-3px,-1px)}100%{transform:translate(2px,2px)}}@keyframes galGlitchC{0%{transform:translate(-3px,1px)}25%{transform:translate(2px,-2px)}50%{transform:translate(-1px,3px)}75%{transform:translate(3px,0px)}100%{transform:translate(-2px,-2px)}}@keyframes galGlitchSlice{0%{clip-path:inset(0 0 0 0)}20%{clip-path:inset(20% 0 60% 0)}40%{clip-path:inset(50% 0 10% 0)}60%{clip-path:inset(10% 0 80% 0)}80%{clip-path:inset(70% 0 5% 0)}100%{clip-path:inset(0 0 0 0)}}[data-amh="gallery-glitch"] .gal-glitch_caption{position:absolute;bottom:0;left:0;right:0;z-index:2;padding:1.25rem;background:linear-gradient(to top,rgba(0,0,0,.7),transparent)}[data-amh="gallery-glitch"] .gal-glitch_caption-title{font-size:1rem;font-weight:500;color:var(--amh-text-primary,#F2F2F2)}[data-amh="gallery-glitch"] .gal-glitch_caption-sub{font-family:monospace;font-size:.6875rem;color:var(--amh-text-accent,#00B6B6);text-transform:uppercase;letter-spacing:.1em;margin-top:.25rem}@media(max-width:991px){[data-amh="gallery-glitch"] .gal-glitch_grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:479px){[data-amh="gallery-glitch"] .gal-glitch_grid{grid-template-columns:1fr}}@media(prefers-reduced-motion:reduce){[data-amh="gallery-glitch"] .gal-glitch_item:hover::before,[data-amh="gallery-glitch"] .gal-glitch_item:hover::after{animation:none!important;opacity:0!important}[data-amh="gallery-glitch"] .gal-glitch_item:hover .gal-glitch_visual{animation:none!important}}')}):console.warn("amh-gallery-glitch: amh-core.js must be loaded first.")}();